/**
 * Nodo - NORMALIZACIÓN PÓLIZA v2
 * Workflow: Inventario Activos -> Supabase v4
 *
 * Recibe TODAS las filas (con y sin placa) para que la herencia
 * contextual funcione correctamente. El filtro de "solo sin placa"
 * se aplica en el siguiente nodo.
 */

const MAX_INHERIT_DISTANCE = 5;

function dequote(x) {
  if (x == null) return '';
  const s = String(x).replace(/\r?\n/g, ' ').trim();
  if (s === '""' || s === "''" || /^"+$/.test(s) || /^'+$/.test(s)) return '';
  return s;
}

function foldTxt(x) {
  return String(x == null ? '' : x)
    .toUpperCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/[^A-Z0-9 ]/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function isBlankText(x) {
  const s = foldTxt(dequote(x));
  return (
    !s ||
    s === 'N A' || s === 'NA' || s === 'NULO' || s === 'NULL' ||
    s === 'NO APLICA' || s === 'SIN INFORMACION' || s === 'SIN INFO' || s === 'NO REGISTRA'
  );
}

function normSerial(s) {
  if (!s) return null;
  let t = String(s)
    .toUpperCase()
    .replace(/\bS\/?N[:\s-]*/g, '')
    .replace(/[^A-Z0-9]/g, '')
    .replace(/^0+/, '');
  return (
    t &&
    !['NA', 'N/A', 'NULL', 'NULO', 'NOAPLICA', 'SININFO', 'SININFORMACION'].includes(t) &&
    t.length >= 5
  ) ? t : null;
}

function fnv1a(str) {
  let h = 0x811c9dc5;
  for (let i = 0; i < str.length; i++) {
    h ^= str.charCodeAt(i);
    h = Math.imul(h, 0x01000193) >>> 0;
  }
  return h.toString(16).padStart(8, '0');
}

function parseMoney(v) {
  if (v == null || v === '') return 0;
  if (typeof v === 'number') return Number.isFinite(v) ? Math.round(v) : 0;
  let s = String(v).trim().replace(/\u00A0/g, ' ').replace(/[^\d,.-]/g, '');
  if (!s) return 0;
  const hasDot = s.includes('.');
  const hasComma = s.includes(',');
  if (hasDot && hasComma) {
    const lastDot = s.lastIndexOf('.');
    const lastComma = s.lastIndexOf(',');
    if (lastComma > lastDot) {
      s = s.replace(/\./g, '').replace(',', '.');
    } else {
      s = s.replace(/,/g, '');
    }
  } else if (hasComma && !hasDot) {
    const parts = s.split(',');
    if (parts.length === 2 && parts[1].length <= 2) {
      s = s.replace(',', '.');
    } else {
      s = s.replace(/,/g, '');
    }
  } else if (hasDot && !hasComma) {
    const parts = s.split('.');
    if (parts.length > 2) {
      s = s.replace(/\./g, '');
    } else if (parts.length === 2 && parts[1].length === 3 && parts[0].length <= 3) {
      s = s.replace(/\./g, '');
    }
  }
  const n = Number(s);
  return Number.isFinite(n) ? Math.round(n) : 0;
}

function pickMoneyRaw(raw) {
  const candidates = [
    raw['VALOR DE REFERENCIA'], raw['VALOR REFERENCIA'],
    raw['VALOR'], raw['SUB TOTAL'], raw['VALOR UNITARIO'],
  ];
  for (const c of candidates) {
    if (c == null) continue;
    const clean = dequote(c);
    if (clean === '') continue;
    const parsed = parseMoney(clean);
    if (parsed > 0) return { raw: c, provided: true, value: parsed };
  }
  return { raw: null, provided: false, value: 0 };
}

const BUILDINGS = [/\b20\s*DE\s*JULIO\b/, /\bPRADO\b/, /\bCOSMOS\b/, /\bROMELIO(?:\s+MARTINEZ)?\b/];
const STOP = new Set(['PC','PARA','DE','DEL','LA','EL','EN','AREA','USO','OFICINA','SALA','LAB','LABORATORIO','DEPARTAMENTO','OF','Y','CON','POR','REEMPLAZO','SEDE']);
const CANON = [
  { re: /\bDIRECCION\s+ADMINISTRATIVA\b/, canon: 'DIRECCION ADMINISTRATIVA' },
  { re: /\bSALUD\s+INTEGRAL\b/, canon: 'SALUD INTEGRAL' },
  { re: /\bREGISTRO(\s+Y\s+CONTROL)?\b/, canon: 'REGISTRO' },
  { re: /\bTESORERIA\b/, canon: 'TESORERIA' },
  { re: /\bADMISIONES?\b/, canon: 'ADMISIONES' },
  { re: /\bMERCADEO\b/, canon: 'MERCADEO' },
  { re: /\bSECRETARIA\b/, canon: 'SECRETARIA' },
  { re: /\bCOORDINACION(\s+ACADEMICA)?\b/, canon: 'COORDINACION' },
  { re: /\bBIENESTAR\b/, canon: 'BIENESTAR' },
  { re: /\bBIBLIOTECA\b/, canon: 'BIBLIOTECA' },
  { re: /\bAUDITORIO\b/, canon: 'AUDITORIO' },
  { re: /\bDOCENTES?\b/, canon: 'DOCENTES' },
  { re: /\bRECEPCION\b/, canon: 'RECEPCION' },
  { re: /\bCOMPRAS\b/, canon: 'COMPRAS' },
  { re: /\bADMINISTRACION\b/, canon: 'ADMINISTRACION' },
  { re: /\bSOPORTE(\s+TECNICO)?\b/, canon: 'SOPORTE TECNICO' },
  { re: /\bTI\b|\bTECNOLOGIA\b|\bSISTEMAS\b/, canon: 'SISTEMAS' },
  { re: /\bPOS(T)?GRADOS?\b/, canon: 'POSGRADOS' },
  { re: /\bPREGRADOS?\b/, canon: 'PREGRADOS' },
  { re: /\bLAB(?:ORATORIO)?\s+DE\s+SISTEMAS\b|\bSALA\s+DE\s+SISTEMAS\b/, canon: 'SALA DE SISTEMAS' },
  { re: /\bLABORATORIO\b/, canon: 'LABORATORIO' },
  { re: /\bCIE\b|\bCENTRO\s+DE\s+INNOVACION\s+EDUCATIVA\b/, canon: 'CIE' },
];
const GENERIC = [
  { re: /\bOFICINA\s+DE\s+([A-Z ]{3,})\b/, prefix: '' },
  { re: /\bSALA\s+DE\s+([A-Z ]{3,})\b/, prefix: 'SALA DE ' },
  { re: /\bLAB(?:ORATORIO)?\s+DE\s+([A-Z ]{3,})\b/, prefix: 'LABORATORIO DE ' },
];

function stripBuildings(text) {
  let s = text;
  for (const r of BUILDINGS) s = s.replace(r, ' ');
  return s.replace(/\s+/g, ' ').trim();
}

function inferUbicacion(text) {
  const raw = foldTxt(text);
  if (!raw) return '';
  const s = stripBuildings(raw);
  for (const item of CANON) if (item.re.test(s)) return item.canon;
  for (const item of GENERIC) {
    const m = s.match(item.re);
    if (m) {
      const candidate = foldTxt(m[1]).split(' ').filter(w => w && !STOP.has(w)).join(' ').trim();
      if (candidate && !BUILDINGS.some(r => r.test(candidate))) return `${item.prefix}${candidate}`.trim();
    }
  }
  const tokens = s.split(' ').filter(w => w && !STOP.has(w));
  for (const token of tokens) {
    if (token === 'CIE') return 'CIE';
    for (const item of CANON) if (item.re.test(` ${token} `)) return token;
  }
  return '';
}

function makeFP(record) {
  const serialNorm = record['SERIAL_NORM'] || normSerial(record['SERIAL']);
  if (serialNorm) return `S:${serialNorm}`;
  const key = [record['TIPO DE ACTIVO'], record['MARCA'], record['MODELO'], record['NOMBRE ACTIVO'], record['DESCRIPCIÓN']].map(foldTxt).join('|');
  return `F:${fnv1a(key)}`;
}

function makeMatchHint(record) {
  return [record['TIPO DE ACTIVO'], record['MARCA'], record['MODELO'], record['NOMBRE ACTIVO'], record['DESCRIPCIÓN']].join('|');
}

function makeCompatKey(record) {
  return [record['TIPO DE ACTIVO'], record['CUENTA CONTABLE'], record['MARCA'], record['EDIFICIO'], record['RESPONSABLE']].map(foldTxt).join('|||');
}

function canInheritFromContext(currentSeq, ctx) {
  if (!ctx) return false;
  const a = Number(currentSeq);
  const b = Number(ctx.seq);
  if (!Number.isFinite(a) || !Number.isFinite(b)) return true;
  return a >= b && a - b <= MAX_INHERIT_DISTANCE;
}

const inputItems = $input.all();
const rows = [];
const lastByCompatKey = new Map();

for (let index = 0; index < inputItems.length; index++) {
  const raw = inputItems[index].json || {};
  const rowNumber = raw.row_number ?? raw['row_number'] ?? raw.rowNumber ?? raw['ROW_NUMBER'] ?? null;
  const seq = Number(rowNumber) || index + 1;
  const rawObservaciones = dequote(raw['OBSERVACIONES']);
  const rawUbicacion = dequote(raw['UBICACIÓN'] ?? raw['UBICACION'] ?? '');
  const rawDescripcion = dequote(raw['DESCRIPCIÓN'] ?? raw['DESCRIPCION'] ?? '');
  const obsSource = rawObservaciones || rawUbicacion || rawDescripcion || '';
  const money = pickMoneyRaw(raw);

  const out = {
    'PLACA': dequote(raw['PLACA']),
    'NOMBRE ACTIVO': foldTxt(dequote(raw['NOMBRE ACTIVO'])),
    'TIPO DE ACTIVO': foldTxt(dequote(raw['TIPO DE ACTIVO'])),
    'CUENTA CONTABLE': foldTxt(dequote(raw['CUENTA CONTABLE'])),
    'DESCRIPCIÓN': foldTxt(rawDescripcion),
    'MARCA': foldTxt(dequote(raw['MARCA'])),
    'MODELO': foldTxt(dequote(raw['MODELO'])).replace(/\s*\/\s*/g, ' '),
    'SERIAL': dequote(raw['SERIAL']),
    'EDIFICIO': foldTxt(dequote(raw['EDIFICIO'] ?? raw['SEDE'] ?? '')),
    'PISO': foldTxt(dequote(raw['PISO'])),
    'BLOQUE': foldTxt(dequote(raw['BLOQUE'])),
    'UBICACIÓN': foldTxt(rawUbicacion),
    'CANTIDAD': Number.parseInt(raw['CANTIDAD'] ?? 1, 10) || 1,
    'VALOR DE REFERENCIA': money.value,
    'RESPONSABLE': foldTxt(dequote(raw['RESPONSABLE'])),
    'row_number': rowNumber,
  };

  const inferredLocation = inferUbicacion(obsSource);
  if (inferredLocation && !BUILDINGS.some(r => r.test(inferredLocation))) out['UBICACIÓN'] = inferredLocation;

  const compatKey = makeCompatKey(out);
  const ctx = lastByCompatKey.get(compatKey);
  const inheritedFields = [];

  if (canInheritFromContext(seq, ctx)) {
    if (isBlankText(out['NOMBRE ACTIVO']) && !isBlankText(ctx.nombreActivo)) { out['NOMBRE ACTIVO'] = ctx.nombreActivo; inheritedFields.push('NOMBRE ACTIVO'); }
    if (isBlankText(out['UBICACIÓN']) && !isBlankText(ctx.ubicacion)) { out['UBICACIÓN'] = ctx.ubicacion; inheritedFields.push('UBICACIÓN'); }
    if (isBlankText(out['DESCRIPCIÓN']) && !isBlankText(ctx.descripcion)) { out['DESCRIPCIÓN'] = ctx.descripcion; inheritedFields.push('DESCRIPCIÓN'); }
    if ((!money.provided || out['VALOR DE REFERENCIA'] === 0) && Number(ctx.valorReferencia) > 0) { out['VALOR DE REFERENCIA'] = Number(ctx.valorReferencia); inheritedFields.push('VALOR DE REFERENCIA'); }
  }

  out['SERIAL_NORM'] = normSerial(out['SERIAL']);
  const fpBase = makeFP(out);
  out['FP_BASE'] = fpBase;
  out['FP'] = fpBase;
  out['MATCH_HINT'] = makeMatchHint(out);
  out['WAS_INHERITED'] = inheritedFields.length > 0;
  out['INHERITED_FROM_ROW'] = inheritedFields.length > 0 ? ctx?.row_number ?? null : null;
  out['INHERITED_FIELDS'] = inheritedFields;

  rows.push(out);

  if (!isBlankText(out['NOMBRE ACTIVO'])) {
    lastByCompatKey.set(compatKey, {
      seq,
      row_number: out['row_number'],
      nombreActivo: out['NOMBRE ACTIVO'],
      ubicacion: out['UBICACIÓN'],
      descripcion: out['DESCRIPCIÓN'],
      valorReferencia: Number(out['VALOR DE REFERENCIA']) || 0,
    });
  }
}

return rows.map(row => ({ json: row }));

/**
 * Nodo - TRANSFORMACIÓN POR CANTIDAD v3
 * Workflow: Inventario Activos -> Supabase v4
 */

function foldTxt(value) {
  return String(value == null ? '' : value)
    .toUpperCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '')
    .replace(/[^A-Z0-9 ]/g, ' ').replace(/\s+/g, ' ').trim();
}

function normSerial(value) {
  if (!value) return null;
  const serial = String(value).toUpperCase()
    .replace(/\bS\/?N[:\s-]*/g, '').replace(/[^A-Z0-9]/g, '').replace(/^0+/, '');
  const invalidSerials = new Set(['NA','N/A','NULL','NULO','NOAPLICA','SININFO','SININFORMACION','NOREGISTRA']);
  if (!serial || serial.length < 5 || invalidSerials.has(serial)) return null;
  return serial;
}

function fnv1a(value) {
  const str = String(value ?? '');
  let hash = 0x811c9dc5;
  for (let i = 0; i < str.length; i++) {
    hash ^= str.charCodeAt(i);
    hash = Math.imul(hash, 0x01000193) >>> 0;
  }
  return hash.toString(16).padStart(8, '0');
}

function toPositiveInt(value, fallback = 1) {
  const n = Number.parseInt(value, 10);
  if (!Number.isFinite(n) || n < 1) return fallback;
  return n;
}

function getRowNumber(record, sourceIndex) {
  return record.row_number ?? record['row_number'] ?? record.ROW_NUMBER ?? record.rowNumber ?? sourceIndex + 1;
}

function makeMatchHint(record) {
  return [record['TIPO DE ACTIVO'], record['MARCA'], record['MODELO'], record['NOMBRE ACTIVO'], record['DESCRIPCIÓN']]
    .map(value => String(value ?? '')).join('|');
}

function makeFallbackBaseFP(record) {
  const serialNorm = record.SERIAL_NORM || normSerial(record.SERIAL);
  if (serialNorm) return `S:${serialNorm}`;
  const key = [record['TIPO DE ACTIVO'], record['MARCA'], record['MODELO'], record['NOMBRE ACTIVO'], record['DESCRIPCIÓN']].map(foldTxt).join('|');
  return `F:${fnv1a(key)}`;
}

function hasRealSerial(record) {
  const serialNorm = record.SERIAL_NORM || normSerial(record.SERIAL);
  const fp = String(record.FP || record.FP_BASE || '');
  return Boolean(serialNorm) || fp.startsWith('S:');
}

function makeUnitFP(record, unitIndex, sourceIndex) {
  const fpBase = record.FP_BASE || record.FP || makeFallbackBaseFP(record);
  if (hasRealSerial(record)) return fpBase;
  const rowNumber = getRowNumber(record, sourceIndex);
  const stableUnitKey = [fpBase, `ROW:${rowNumber}`, `UNIT:${unitIndex}`].join('|');
  return `F:${fnv1a(stableUnitKey)}`;
}

const inputItems = $input.all();
const output = [];

for (let sourceIndex = 0; sourceIndex < inputItems.length; sourceIndex++) {
  const raw = inputItems[sourceIndex].json || {};
  const rowNumber = getRowNumber(raw, sourceIndex);
  const originalQuantity = toPositiveInt(raw.CANTIDAD, 1);
  const serialNorm = raw.SERIAL_NORM || normSerial(raw.SERIAL);
  const fpBase = raw.FP_BASE || raw.FP || makeFallbackBaseFP({ ...raw, SERIAL_NORM: serialNorm });
  const matchHint = raw.MATCH_HINT || makeMatchHint(raw);
  const serialBased = hasRealSerial({ ...raw, FP_BASE: fpBase, SERIAL_NORM: serialNorm });

  for (let unitIndex = 1; unitIndex <= originalQuantity; unitIndex++) {
    const unitFP = makeUnitFP({ ...raw, row_number: rowNumber, FP_BASE: fpBase, SERIAL_NORM: serialNorm }, unitIndex, sourceIndex);
    output.push({
      json: {
        ...raw,
        row_number: rowNumber,
        SERIAL_NORM: serialNorm,
        FP_BASE: fpBase,
        MATCH_HINT: matchHint,
        FP: unitFP,
        CANTIDAD: 1,
        CANTIDAD_ORIGINAL: originalQuantity,
        UNIT_INDEX: unitIndex,
        UNIT_TOTAL: originalQuantity,
        WAS_EXPANDED_BY_QUANTITY: originalQuantity > 1,
        HAS_REAL_SERIAL: serialBased,
        SERIAL_WITH_QUANTITY_WARNING: serialBased && originalQuantity > 1,
      }
    });
  }
}

return output;

/* ==================== MAPEOS DE CATÁLOGOS ==================== */
const BUILDING_MAP = {
  'COSMOS':               { id: 1, code: '01' },
  'CONSULTORIO JURIDICO': { id: 2, code: '02' },
  '20 DE JULIO':          { id: 3, code: '03' },
  'PRADO':                { id: 4, code: '04' },
  'ROMELIO':              { id: 5, code: '05' },
  'ROMELIO MARTINEZ':     { id: 5, code: '05' },
  'CALLE 79':             { id: 6, code: '06' },
  'CALLE79':              { id: 6, code: '06' },
};
const ASSET_TYPE_MAP = {
  'PLANTAS DUCTOS Y TUNELES':               '45',
  'PLANTAS DUCTOS TUNELES':                 '45',
  'MAQUINARIA Y EQUIPO':                    '55',
  'MAQUINARIA EQUIPO':                      '55',
  'EQUIPO MEDICO Y CIENTIFICO':             '60',
  'EQUIPO MEDICO CIENTIFICO':               '60',
  'MUEBLES ENSERES Y EQUIPO DE OFICINA':    '65',
  'MUEBLES ENSERES EQUIPO OFICINA':         '65',
  'MUEBLES Y ENSERES':                      '65',
  'EQUIPOS DE COMUNICACION Y COMPUTACION':  '70',
  'EQUIPOS COMUNICACION COMPUTACION':       '70',
  'EQUIPO DE COMPUTO':                      '70',
  'EQUIPOS DE TRANSPORTE TRACCION Y ELEVACION': '75',
  'EQUIPOS TRANSPORTE TRACCION ELEVACION':  '75',
};
const VALID_CODES = ['45', '55', '60', '65', '70', '75'];
const MONTHS = ['ENERO','FEBRERO','MARZO','ABRIL','MAYO','JUNIO','JULIO','AGOSTO','SEPTIEMBRE','OCTUBRE','NOVIEMBRE','DICIEMBRE'];

function foldTxt(x) {
  return String(x == null ? '' : x)
    .toUpperCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '')
    .replace(/[^A-Z0-9 ]/g, ' ').replace(/\s+/g, ' ').trim();
}
function resolveAssetTypeCode(tipoActivo, cuentaContable) {
  const cc = String(cuentaContable || '').replace(/\D/g, '').slice(0, 2);
  if (VALID_CODES.includes(cc)) return cc;
  return ASSET_TYPE_MAP[foldTxt(tipoActivo)] || null;
}
function resolveBuilding(edificio) {
  return BUILDING_MAP[foldTxt(edificio)] || null;
}

/* ==================== PROCESAMIENTO ==================== */
const items = $input.all();
const valid = [];
const invalid = [];
const now = new Date();
const sourceSheet = `n8n_poliza_${MONTHS[now.getMonth()]}_${now.getFullYear()}`;

for (let i = 0; i < items.length; i++) {
  const raw = items[i].json;
  const errors = [];

  const building = resolveBuilding(raw['EDIFICIO']);
  if (!building) errors.push(`Edificio desconocido: '${raw['EDIFICIO']}'`);

  const assetTypeCode = resolveAssetTypeCode(raw['TIPO DE ACTIVO'], raw['CUENTA CONTABLE']);
  if (!assetTypeCode) errors.push(`Tipo no mapeado: '${raw['TIPO DE ACTIVO']}' / CC: '${raw['CUENTA CONTABLE']}'`);

  if (!raw['NOMBRE ACTIVO'] || String(raw['NOMBRE ACTIVO']).trim() === '') errors.push('NOMBRE ACTIVO vacío');

  if (errors.length > 0) {
    invalid.push({ name: raw['NOMBRE ACTIVO'], errors });
  } else {
    valid.push({
      json: {
        row_number:        raw.row_number ?? null,
        city_code:         '1',
        building_id:       building.id,
        building_code:     building.code,
        asset_type_code:   assetTypeCode,
        name:              raw['NOMBRE ACTIVO'],
        description:       raw['DESCRIPCIÓN'] || null,
        puc_account:       assetTypeCode,
        brand:             raw['MARCA'] || null,
        model:             raw['MODELO'] || null,
        serial:            raw['SERIAL'] || null,
        quantity:          1,
        reference_value:   raw['VALOR DE REFERENCIA'] || 0,
        location:          raw['UBICACIÓN'] || null,
        floor:             raw['PISO'] || null,
        block:             raw['BLOQUE'] || null,
        responsable_raw:   raw['RESPONSABLE'] || null,
        status:            'ACTIVO',
        source_sheet:      sourceSheet,
        content_hash:      raw['FP'],
        incorporation_year: now.getFullYear(),
      }
    });
  }
}

const stats = {
  valid_count:   valid.length,
  invalid_count: invalid.length,
  invalid_items: invalid,
};

return valid.map((item, idx) => {
  const json = { ...item.json };
  if (idx === 0) json._stats = stats;
  return { json };
});

// Nodo: Agregación de Resultados
// Propósito: consolidar el cierre del flujo y preparar un payload limpio para sync_log.

const insertResults = $('PostgreSQL - INSERT con Placa').all();
const mappingOutput = $('Mapeo a Schema PostgreSQL').all();
const sheetUpdateResults = $input.all();

function hasValue(value) {
  return value !== null && value !== undefined && String(value).trim() !== '';
}

function isImportedMark(value) {
  return String(value ?? '').trim().toUpperCase() === 'IMPORTADO';
}

const firstMappingItem = mappingOutput.find((item) => {
  return item.json && hasValue(item.json.source_sheet);
});

const sourceSheet = firstMappingItem?.json?.source_sheet ?? null;

const rawStats = mappingOutput[0]?.json?._stats;

const stats = rawStats ?? {
  valid_count: insertResults.length,
  invalid_count: 0,
  invalid_items: [],
};

const insertados = insertResults.filter((item) => {
  const row = item.json ?? {};
  return row.id != null;
}).length;

const fallidos = Math.max(0, insertResults.length - insertados);

const validCount = Number(stats.valid_count ?? insertResults.length);
const invalidCount = Number(stats.invalid_count ?? 0);

const totalPoliza = validCount + invalidCount;

const erroresValidacion = Array.isArray(stats.invalid_items)
  ? stats.invalid_items
  : [];

const filasActualizadas = sheetUpdateResults.filter((item) => {
  const row = item.json ?? {};

  return (
    row.row_number != null &&
    isImportedMark(row.PLACA_SIGAF)
  );
});

const warnings = [];

if (!sourceSheet) {
  warnings.push('No se encontró source_sheet en el nodo "Mapeo a Schema PostgreSQL".');
}

if (validCount !== insertResults.length) {
  warnings.push(
    `Diferencia entre válidos mapeados (${validCount}) e intentos de inserción (${insertResults.length}).`
  );
}

if (filasActualizadas.length !== insertados) {
  warnings.push(
    `Diferencia entre registros insertados (${insertados}) y filas marcadas como IMPORTADO en Google Sheets (${filasActualizadas.length}).`
  );
}

const estadoSync =
  fallidos > 0 || invalidCount > 0 || warnings.length > 0
    ? 'COMPLETADO_CON_OBSERVACIONES'
    : 'COMPLETADO';

return [
  {
    json: {
      source_sheet: sourceSheet,

      total_poliza: totalPoliza,
      procesados_validos: validCount,
      insertados,
      fallidos,
      rechazados_validacion: invalidCount,

      filas_actualizadas_sheet: filasActualizadas.length,
      errores_validacion: erroresValidacion,

      estado_sync: estadoSync,
      warnings,

      listo_para_sync_log: Boolean(sourceSheet),
      created_at_runtime: new Date().toISOString(),
    },
  },
];

