  /* ─────────────────────────────────────────────
     DATOS DEL SYNC
  ───────────────────────────────────────────── */
  const sync       = $json ?? {};
  const insertados = Number(sync.insertados ?? 0);
  const fallidos   = Number(sync.fallidos   ?? 0);

  /* ─────────────────────────────────────────────
     MAPEO DESDE NODO ANTERIOR
     FIX: mappingItems puede llegar vacío si la
     ejecución viene por ruta merge/aggregate.
     Se maneja con fallback explícito.
  ───────────────────────────────────────────── */
  const mappingItems = $('Mapeo a Schema PostgreSQL').all().map((i) => i.json ?? {});
  const rows         = mappingItems.slice(0, insertados);
  const detailAvailable = rows.length > 0;

  /* ─────────────────────────────────────────────
     CATÁLOGOS
  ───────────────────────────────────────────── */
  const TYPE_NAMES = {
    '45': 'Plantas, Ductos y Túneles',
    '55': 'Maquinaria y Equipo',
    '60': 'Equipo Médico y Científico',
    '65': 'Muebles, Enseres y Eq. de Oficina',
    '70': 'Equipos de Comunicación y Cómputo',
    '75': 'Equipos de Transporte y Tracción',
  };

  const TYPE_ICONS = {
    '45': '🏭', '55': '⚙️', '60': '🔬',
    '65': '🪑', '70': '💻', '75': '🚛',
  };

  /* ─────────────────────────────────────────────
     FORMATTERS
  ───────────────────────────────────────────── */
  const currency = new Intl.NumberFormat('es-CO', {
    style: 'currency', currency: 'COP', maximumFractionDigits: 0,
  });

  const dateFormatter = new Intl.DateTimeFormat('es-CO', {
    timeZone: 'America/Bogota',
    weekday: 'long', year: 'numeric', month: 'long',
    day: '2-digit', hour: '2-digit', minute: '2-digit',
  });

  const createdAt   = sync.created_at ? new Date(sync.created_at) : new Date();
  const fechaProceso = dateFormatter.format(createdAt);
  const fechaFormateada = fechaProceso.charAt(0).toUpperCase() + fechaProceso.slice(1);

  /* ─────────────────────────────────────────────
     TOTALES Y DISTRIBUCIÓN
  ───────────────────────────────────────────── */
  const totalValue = rows.reduce((sum, row) => {
    const v = Number(row.reference_value ?? 0);
    return sum + (Number.isFinite(v) ? v : 0);
  }, 0);

  const byType = new Map();
