    if (!byType.has(code)) byType.set(code, { label, icon, count: 0, value: 0 });
    const entry = byType.get(code);
    entry.count += 1;
    entry.value += Number.isFinite(value) ? value : 0;
  }

  const distributionRows = Array.from(byType.values());
  const maxCount         = distributionRows.reduce((m, e) => Math.max(m, e.count), 1);

  /* ─────────────────────────────────────────────
