        </td>
      </tr>`;
  } else {
    distributionHtml = distributionRows.map((entry, idx) => {
      const pct     = insertados > 0 ? Math.round((entry.count / insertados) * 100) : 0;
      const barPct  = maxCount > 0    ? Math.round((entry.count / maxCount) * 100) : 0;
      const rowBg   = idx % 2 === 0 ? '#f8fbff' : '#ffffff';
      return `
        <tr>
          <td style="padding:14px 18px; border-bottom:1px solid #e4edf8; background:${rowBg}; vertical-align:middle;">
            <div style="font-size:12px; font-weight:700; color:#0b2447; margin-bottom:7px;">
              ${entry.icon}&nbsp;&nbsp;${entry.label}
            </div>
            <div style="height:5px; background:#dce8f6; border-radius:99px; overflow:hidden;">
              <div style="height:5px; width:${barPct}%; background:linear-gradient(90deg,#0d64d8,#0a9ef0); border-radius:99px;"></div>
