              background:linear-gradient(135deg,#0d64d8,#0846a0); color:#ffffff; font-weight:800; font-size:13px;">
              ${entry.count}
            </span>
          </td>
          <td style="padding:14px 18px; border-bottom:1px solid #e4edf8; background:${rowBg}; text-align:right; vertical-align:middle; color:#087a3d; font-weight:700; font-size:12px;">
            ${currency.format(entry.value)}
          </td>
        </tr>`;
    }).join('');
  }

  /* ─────────────────────────────────────────────
     ALERTA DE FALLOS
  ───────────────────────────────────────────── */
  const errorBanner = hasErrors ? `
    <tr>
      <td style="padding:0 36px 28px;">
