/**
 * Nodo - Agrupar Filas Importadas por Fila de Póliza
 *
 * Marca como IMPORTADO cada fila original de la póliza que tuvo al menos
 * un activo insertado correctamente en Supabase.
 *
 * No devuelve placas ni trazabilidad técnica hacia Google Sheets.
 * La columna PLACA_SIGAF funciona únicamente como bandera operativa:
 *
 * - Vacío: pendiente de importar.
 * - IMPORTADO: ya cargado en Supabase/SIGAF.
 *
 * Requiere que "Mapeo a Schema PostgreSQL" incluya row_number en su output.
 */

const insertResults = $input.all();
const mapeoResults = $('Mapeo a Schema PostgreSQL').all();

if (insertResults.length !== mapeoResults.length) {
  console.warn(
    `[Agrupar Filas Importadas] Conteo asimétrico: INSERT=${insertResults.length}, Mapeo=${mapeoResults.length}`
  );
}

const importedRows = new Set();

for (let i = 0; i < insertResults.length; i++) {
  const insertedId = insertResults[i]?.json?.id;
  const generatedPlate = insertResults[i]?.json?.plate;

  if (insertedId == null || !generatedPlate) continue;

  const rowNumber = mapeoResults[i]?.json?.row_number ?? null;
  if (rowNumber == null) continue;

  importedRows.add(String(rowNumber));
}

const results = Array.from(importedRows).map((rowNumber) => ({
  json: {
    row_number: Number(rowNumber),
    PLACA_SIGAF: 'IMPORTADO',
  },
}));

if (results.length === 0) {
  return [
    {
      json: {
        row_number: null,
        PLACA_SIGAF: '',
        _no_updates: true,
      },
    },
  ];
}

return results;
